SELECT * FROM comment
WHERE biz_id = #{bizId}
ORDER BY timestamp DESC

SELECT * FROM comment
WHERE user_id = #{userId}
ORDER BY timestamp DESC

SELECT biz_id AS bizId, 0 AS behaviorType, UNIX_TIMESTAMP(timestamp) * 1000 AS timestamp
FROM comment
WHERE user_id = #{userId}
ORDER BY timestamp DESC
LIMIT #{limit}

SELECT comment_id, user_id, biz_id, score, content, timestamp
FROM comment
WHERE biz_id = #{bizId}
ORDER BY timestamp DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM comment
WHERE biz_id = #{bizId}
